$ErrorActionPreference = "Stop"

function Escape-Xml([string]$text) {
  if ($null -eq $text) { return "" }
  return [System.Security.SecurityElement]::Escape($text)
}

function Add-Paragraph([System.Collections.Generic.List[string]]$parts, [string]$text, [string]$style = "Normal") {
  $parts.Add("<w:p><w:pPr><w:pStyle w:val=`"$style`"/></w:pPr><w:r><w:t xml:space=`"preserve`">$(Escape-Xml $text)</w:t></w:r></w:p>")
}

function Add-Code([System.Collections.Generic.List[string]]$parts, [string]$code) {
  foreach ($line in ($code -split "`r?`n")) {
    $parts.Add("<w:p><w:pPr><w:pStyle w:val=`"Code`"/></w:pPr><w:r><w:t xml:space=`"preserve`">$(Escape-Xml $line)</w:t></w:r></w:p>")
  }
}

function Add-PageBreak([System.Collections.Generic.List[string]]$parts) {
  $parts.Add('<w:p><w:r><w:br w:type="page"/></w:r></w:p>')
}

$root = Resolve-Path "."
$docDir = Join-Path $root "doc"
if (!(Test-Path $docDir)) {
  New-Item -ItemType Directory -Path $docDir | Out-Null
}

$outPath = Join-Path $docDir "4-Пояснювальна-записка_зелена-енергетика_ТЕКСТОВА-ЧАСТИНА_виправлено.docx"
$tmp = Join-Path $env:TEMP ("course-note-" + [guid]::NewGuid().ToString("N"))
New-Item -ItemType Directory -Path $tmp | Out-Null
New-Item -ItemType Directory -Path (Join-Path $tmp "_rels") | Out-Null
New-Item -ItemType Directory -Path (Join-Path $tmp "word") | Out-Null

$parts = New-Object System.Collections.Generic.List[string]

Add-Paragraph $parts "ВСТУП" "H1"
Add-Paragraph $parts "У сучасних умовах розвитку цифрового середовища вебсайт перестав бути лише допоміжним засобом представлення організації, оскільки саме через вебресурс користувач найчастіше отримує перше уявлення про діяльність компанії, її цінності, професійність і готовність до комунікації. Для компанії, що працює у сфері зеленої енергетики, якісно розроблений сайт має особливе значення, адже ця галузь поєднує технічну складність, екологічну відповідальність і потребу в доступному поясненні переваг відновлюваних джерел енергії."
Add-Paragraph $parts "Тема курсового проєкту – «Розроблення сайту компанії у сфері зеленої енергетики». Її актуальність зумовлена тим, що питання енергоефективності, зменшення залежності від традиційних джерел енергії та переходу до екологічно безпечних рішень дедалі частіше стають предметом зацікавлення як для бізнесу, так і для приватних користувачів. Водночас для зрозумілого представлення таких послуг необхідний вебсайт, який поєднує візуальну привабливість, логічну структуру та прості механізми зв’язку з компанією."
Add-Paragraph $parts "Метою курсового проєкту є створення багатосторінкового інформаційного вебсайту компанії у сфері зеленої енергетики, який забезпечує ознайомлення користувача з діяльністю організації, її підходом до роботи, командою, контактною інформацією та тематичними матеріалами. Під час розроблення проєкту передбачалося не лише сформувати HTML-структуру сторінок, а й розробити єдине стилістичне оформлення, використати графічні ресурси та реалізувати базову інтерактивність засобами JavaScript."
Add-Paragraph $parts "Об’єктом розроблення є вебсайт компанії, що презентує рішення у сфері відновлюваної енергетики. Предметом розроблення є структура сторінок, стилізація інтерфейсу, компонування інформаційних блоків і функціональні елементи, які забезпечують взаємодію користувача з ресурсом. У межах практичної частини створено головну сторінку «index.html», сторінку «about.html», сторінку «team.html», сторінку «contact.html», спільний файл стилів «styles/style.css» і файл сценаріїв «script/app.js»."
Add-Paragraph $parts "У процесі виконання роботи було використано мову розмітки HTML, каскадні таблиці стилів CSS і мову програмування JavaScript. Для візуального оформлення проєкту підключено шрифт «Open Sans» через сервіс Google Fonts, а також бібліотеку Font Awesome, яка застосовується для іконок у кнопках та інтерфейсних елементах. Графічні матеріали зберігаються в папці «images», де розміщено фонові зображення, логотип, іконки, фотографії експертів, зображення клієнтів і матеріали для блогового блоку."
Add-Paragraph $parts "Практична цінність проєкту полягає в тому, що розроблений вебсайт може бути використаний як основа для презентаційного ресурсу компанії, яка надає послуги у сфері зеленої енергетики. Його структура дозволяє користувачу швидко перейти до інформації про компанію, переглянути команду, ознайомитися з контактними даними та скористатися формою зв’язку, що є важливим для комунікації між організацією і потенційними клієнтами."
Add-Paragraph $parts "Пояснювальна записка побудована таким чином, щоб послідовно розкрити етапи виконання курсового проєкту: від аналізу предметної області та структури сторінок до опису верстки, стилізації, інтерактивних компонентів і перевірки працездатності вебсайту. Оскільки зміст і додатки формуються окремо, у цій частині подано основний текст записки, підписи до рисунків і приклади коду, які безпосередньо стосуються реалізованого проєкту."

Add-PageBreak $parts
Add-Paragraph $parts "1 АНАЛІЗ ПРЕДМЕТНОЇ ОБЛАСТІ ТА СТРУКТУРИ ПРОЄКТУ" "H1"
Add-Paragraph $parts "Перш ніж переходити до верстки вебсторінок, необхідно визначити, яку інформаційну роль виконує майбутній вебресурс і яким чином його структура має відповідати очікуванням користувача. Сайт компанії у сфері зеленої енергетики повинен не лише повідомляти загальні відомості про діяльність організації, а й формувати у відвідувача відчуття надійності, сучасності та професійного підходу до реалізації енергетичних рішень."
Add-Paragraph $parts "Предметна область проєкту пов’язана з відновлюваними джерелами енергії, серед яких у матеріалах сайту згадуються сонячна енергія, вітрова енергія, гідроенергетика, зарядка електромобілів, енергоефективні рішення та технології, орієнтовані на зменшення негативного впливу на довкілля. Оскільки така тематика може бути складною для частини аудиторії, інформація на сайті подається у вигляді коротких блоків, які швидко читаються та супроводжуються візуальними акцентами."

Add-Paragraph $parts "1.1 Постановка задачі та призначення вебсайту" "H2"
Add-Paragraph $parts "Завданням курсового проєкту є розроблення вебсайту, який презентує діяльність компанії, що працює із сучасними рішеннями у сфері зеленої енергетики. Вебресурс повинен забезпечувати зручне ознайомлення з основною інформацією, швидкий перехід між сторінками, можливість перегляду контактів, а також наявність інтерактивних елементів, які роблять роботу з сайтом комфортнішою."
Add-Paragraph $parts "Цільовою аудиторією сайту можуть бути приватні клієнти, представники бізнесу та користувачі, які цікавляться переходом на відновлювані джерела енергії. Саме тому вміст сторінок сформовано так, щоб відвідувач спочатку побачив загальний меседж про сталий розвиток, а потім поступово перейшов до детальнішої інформації про напрями діяльності, команду, досягнення, відповіді на поширені запитання та контактні можливості."
Add-Paragraph $parts "Основна сторінка «index.html» виконує роль презентаційного центру проєкту, оскільки вона містить найбільшу кількість секцій і дає загальне уявлення про компанію. Сторінка «about.html» поглиблює інформацію про місію та підхід до роботи. Сторінка «team.html» знайомить користувача з працівниками компанії, а сторінка «contact.html» забезпечує доступ до контактних даних, форми повідомлення та інтегрованої карти."
Add-Paragraph $parts "Рисунок 1.1 – Загальна структура вебсайту компанії у сфері зеленої енергетики" "Figure"
Add-Paragraph $parts "Для реалізації поставленої задачі було обрано статичну структуру сайту, за якої кожна сторінка зберігається в окремому HTML-файлі. Такий підхід є доцільним для навчального курсового проєкту, оскільки він дозволяє безпосередньо продемонструвати навички створення розмітки, оформлення сторінок, організації файлів і написання простих сценаріїв."

Add-Paragraph $parts "1.2 Аналіз структури макету" "H2"
Add-Paragraph $parts "Аналіз структури макету передбачає розгляд того, як розміщені основні інформаційні блоки сайту, якою є логіка переходів між сторінками та яким способом користувач поступово отримує відомості про компанію. У межах цього курсового проєкту макет розглядається за фактично реалізованими сторінками, оскільки окремий файл графічного макету у складі проєкту не подано. Тому подальший опис спирається на структуру HTML-документів і візуальне компонування сторінок у браузері."
Add-Paragraph $parts "Структура вебсайту компанії у сфері зеленої енергетики складається з головної сторінки «index.html» та трьох підпорядкованих сторінок: «about.html», «team.html» і «contact.html». Головна сторінка виконує роль центральної презентаційної сторінки, тоді як інші сторінки деталізують окремі напрями інформації: опис компанії, склад команди та контактні дані. Такий розподіл є логічним, оскільки він не перевантажує одну сторінку всією інформацією, але водночас залишає користувачу можливість швидко перейти до потрібного розділу."
Add-Paragraph $parts "Рисунок 1.2 – Структура вебсайту компанії у сфері зеленої енергетики" "Figure"
Add-Paragraph $parts "Перехід між сторінками забезпечується головним меню, яке розташоване у верхній частині сторінок. У макеті цей блок є одним із найважливіших, тому що він формує навігаційну основу вебресурсу. Логотип розміщено ліворуч і оформлено як посилання на головну сторінку, а пункти меню дають змогу перейти до сторінок «Про нас», «Команда» та «Контакти». Праворуч розташовано кнопку «Зв'язатися», яка відкриває модальну форму."
Add-Paragraph $parts "Код структури головного меню у файлі «index.html» наведено нижче:"
Add-Code $parts @'
<nav class="header-nav">
  <div class="content-wrap d-flex justify-between vertical-center h-full">
    <div class="d-flex">
      <div class="main-logo">
        <a href="index.html">
          <img src="images/logo.svg" alt="logo">
        </a>
      </div>
      <ul class="main-menu d-flex vertical-center">
        <li><a href="about.html">Про нас</a></li>
        <li><a href="team.html">Команда</a></li>
        <li><a href="contact.html">Контакти</a></li>
      </ul>
    </div>
    <button class="header-btn modal-btn">Зв'язатися</button>
  </div>
</nav>
'@
Add-Paragraph $parts "Наведений фрагмент показує, що навігаційний блок побудовано на основі елемента «nav», який семантично позначає область переходів між сторінками. Для пунктів меню використано список «ul» з класом «main-menu», а для вирівнювання елементів застосовано допоміжні класи «d-flex», «justify-between» і «vertical-center». У реальному коді меню містить також додатковий пункт, проте в межах пояснювальної записки аналізуються основні сторінки, які використовуються для представлення компанії."
Add-Paragraph $parts "Головна сторінка макету має послідовну вертикальну структуру, яка починається з першого екрана та завершується футером. Перший екран містить фонове зображення, навігацію, слоган, заголовок, короткий опис і кнопки дії. Саме ця частина макету формує початкове сприйняття сайту, оскільки користувач одразу бачить тему зеленої енергетики та основну ідею – рішення для сталого розвитку."
Add-Paragraph $parts "Рисунок 1.3 – Перший екран головної сторінки сайту" "Figure"
Add-Paragraph $parts "Після першого екрана в макеті розміщено секцію «partners», яка демонструє партнерів компанії. Вона має темний зелений фон, заголовок «Наші партнери» та ряд графічних блоків із логотипами. У структурі сторінки ця секція працює як елемент підсилення довіри, оскільки партнерські логотипи створюють уявлення про зв’язки компанії з іншими організаціями."
Add-Paragraph $parts "Рисунок 1.4 – Секція «Наші партнери» у макеті сайту" "Figure"
Add-Paragraph $parts "Наступним блоком є секція «promo-section», яка поєднує перелік напрямів зеленої енергетики та велике тематичне зображення. У лівій частині розміщено список напрямів, серед яких виділено пункт «Сонячна енергія», що має короткий опис і посилання «Переглянути». У правій частині використано блок «promo-section-img», для якого фонове зображення задається через CSS. Така побудова дозволяє одночасно подати зміст і візуальний акцент."
Add-Code $parts @'
<section class="section promo-section">
  <div class="content-wrap d-flex justify-between">
    <div class="promo-section-content d-flex">
      <div class="promo-section-content-title">
        Енергія, що працює на майбутнє
      </div>
      <div class="promo-section-content-list">
        <ul>
          <li>Зарядка електромобілів</li>
          <li class="list-item-active">Сонячна енергія</li>
          <li>Вітрова енергія</li>
          <li>Гідроенергетика</li>
        </ul>
      </div>
    </div>
    <div class="promo-section-img cover-bg"></div>
  </div>
</section>
'@
Add-Paragraph $parts "Рисунок 1.5 – Секція напрямів зеленої енергетики у макеті головної сторінки" "Figure"
Add-Paragraph $parts "Далі в макеті розташовано інформаційний блок «about», який містить короткий опис компанії та набір кількісних показників. Ліва частина секції призначена для тексту про діяльність компанії, а права частина – для показників «5,000 Mwh», «2,500+», «10,000+» і «15%». Така композиція дозволяє поєднати пояснювальний текст із короткими числовими акцентами, які швидко сприймаються користувачем."
Add-Paragraph $parts "Рисунок 1.6 – Інформаційна секція про компанію та її показники" "Figure"
Add-Paragraph $parts "Окремий блок «section-about-us» дублює загальну ідею про компанію в більш презентаційній формі, після чого користувач переходить до секції «section-expetrs». У цій частині макету відображаються картки експертів із фотографіями, іменами та посадами. Хоча назва класу «section-expetrs» має технічну неточність у написанні, у записці вона подається відповідно до фактичного коду проєкту."
Add-Paragraph $parts "Рисунок 1.7 – Секція «Наші експерти» у макеті головної сторінки" "Figure"
Add-Paragraph $parts "Після секції експертів розміщено блок «section-testimonials», у якому подано відгуки клієнтів. Макет цієї частини побудований на картках із текстом відгуку, зображенням клієнта, іменем і коротким описом його статусу. Використання карток є доречним, оскільки кожен відгук виступає окремою завершеною одиницею інформації."
Add-Paragraph $parts "Рисунок 1.8 – Секція відгуків клієнтів" "Figure"
Add-Paragraph $parts "У нижній частині головної сторінки розміщено секцію «title-section» із коротким закликом до взаємодії, FAQ-блок «faq-section», блоговий блок «blog-section» і секцію «form-section». FAQ-блок допомагає відповісти на типові запитання щодо зеленої енергії, блоговий блок демонструє тематичні матеріали, а форма підписки завершує сторінку пропозицією отримувати оновлення. Така послідовність є логічною, оскільки після ознайомлення з основною інформацією користувачу пропонується подальший контакт із компанією."
Add-Paragraph $parts "Рисунок 1.9 – Нижні інформаційні блоки головної сторінки" "Figure"
Add-Paragraph $parts "Сторінка «about.html» у макеті має простішу структуру, оскільки її основне завдання полягає в розкритті місії та підходу компанії. Вона містить верхній блок із заголовком «Про нас», секцію з текстовими підрозділами «Наша місія» і «Наш підхід», блок досягнень та відеосекцію «Наше бачення». Такий склад сторінки дозволяє подати додаткову інформацію про компанію без надлишкового дублювання головної сторінки."
Add-Paragraph $parts "Рисунок 1.10 – Структура сторінки «Про нас»" "Figure"
Add-Paragraph $parts "Сторінка «team.html» побудована як послідовність однотипних секцій «team-member», кожна з яких містить ім’я фахівця, посаду, короткий опис і фотографію. Повторення однакового шаблону є доцільним, оскільки воно робить сторінку передбачуваною, а інформацію про працівників – легкою для порівняння."
Add-Paragraph $parts "Рисунок 1.11 – Структура сторінки «Команда»" "Figure"
Add-Paragraph $parts "Сторінка «contact.html» завершує основну структуру макету, оскільки саме вона забезпечує практичну взаємодію користувача з компанією. Вона містить блок «contact-info» з телефоном, поштою, адресою та графіком роботи, форму «contact-form» для повідомлення, а також секцію «map-section» з інтегрованою картою. Завдяки цьому сторінка поєднує текстову контактну інформацію, форму зворотного зв’язку та просторову прив’язку місця розташування."
Add-Paragraph $parts "Рисунок 1.12 – Структура сторінки «Контакти»" "Figure"
Add-Paragraph $parts "Отже, структура макету побудована за принципом поступового переходу від загальної презентації компанії до конкретних способів взаємодії. Головна сторінка виконує роль розгорнутої вітрини вебресурсу, а підпорядковані сторінки деталізують окремі змістові напрями. Така організація є доречною для корпоративного сайту у сфері зеленої енергетики, оскільки вона дозволяє одночасно подати іміджеву, інформаційну та контактну складові."

Add-Paragraph $parts "1.3 Визначення технологій та інструментів" "H2"
Add-Paragraph $parts "Під час розроблення проєкту використано три базові технології клієнтської веброзробки: HTML, CSS і JavaScript. HTML застосовано для створення семантичної структури сторінок, розміщення заголовків, форм, посилань, зображень і контейнерів. CSS використано для формування зовнішнього вигляду, зокрема кольорової палітри, відступів, розмірів елементів, фонових зображень, сіток і станів наведення. JavaScript забезпечує роботу інтерактивних компонентів, які не потребують серверної частини."
Add-Paragraph $parts "Для типографіки використано шрифт «Open Sans», який підключено через Google Fonts. Такий шрифт добре підходить для інформаційного сайту, оскільки має нейтральний вигляд і залишається читабельним у заголовках та абзацах. Іконки підключено через Font Awesome, що видно з використання класів на зразок «fa-solid» і «fa-arrow-right»."
Add-Paragraph $parts "У проєкті активно застосовуються допоміжні CSS-класи, які відповідають за вирівнювання та повторювані властивості. Наприклад, клас «d-flex» задає елементам модель Flexbox, клас «justify-between» розподіляє простір між дочірніми елементами, а клас «cover-bg» уніфікує роботу з фоновими зображеннями."
Add-Code $parts @'
.d-flex {
  display: flex;
}
.justify-between {
  justify-content: space-between;
}
.cover-bg {
  background-position: center;
  background-repeat: no-repeat;
  background-size: cover;
}
'@
Add-Paragraph $parts "Наявність таких класів спрощує верстку, оскільки однакові правила не дублюються для кожного блоку окремо. Водночас цей підхід дає змогу швидко змінювати розташування елементів у різних частинах сторінки, не створюючи надмірної кількості унікальних стилів."
Add-Paragraph $parts "Важливою вимогою до інформаційного вебсайту є логічність подання матеріалу, оскільки користувач не повинен витрачати значний час на пошук ключових відомостей. У цьому проєкті інформація поділена на сторінки та секції відповідно до змістового призначення: загальна презентація компанії подається на головній сторінці, поглиблена інформація про місію – на сторінці «about.html», персонал компанії – на сторінці «team.html», а способи комунікації – на сторінці «contact.html». Така структура є зрозумілою, тому що вона відповідає типовій поведінці користувача, який спершу ознайомлюється з основною пропозицією, а потім переходить до детальніших розділів."
Add-Paragraph $parts "Під час аналізу структури було враховано, що сайт не містить складної бізнес-логіки, каталогу товарів або системи авторизації, тому його основне завдання полягає у формуванні цілісної інформаційної картини. Через це найбільше значення мають не алгоритмічні компоненти, а якість верстки, стабільність навігації, правильна робота форм і візуальна послідовність. Саме ці складові визначають, наскільки професійним виглядає вебресурс для відвідувача."
Add-Paragraph $parts "З позиції користувацького досвіду важливо, що на сторінках повторюються одні й ті самі елементи керування. Логотип, головне меню, кнопка «Зв'язатися» та футер присутні на основних сторінках, завдяки чому користувач може передбачити, де розташовані потрібні йому посилання. Така повторюваність не є недоліком, оскільки для корпоративного сайту вона забезпечує стабільність взаємодії та зменшує кількість дій, які потрібно виконати для переходу до потрібної інформації."
Add-Paragraph $parts "Окремої уваги потребує вибір візуальних матеріалів, оскільки тема зеленої енергетики значною мірою сприймається через образи природи, технологій і сталого розвитку. У проєкті використано фонові зображення для першого екрана, промо-блоку, форми підписки та футера, а також окремі фотографії для експертів, клієнтів і блогових матеріалів. Це дає змогу уникнути суто текстового подання, яке було б менш переконливим для презентаційного вебресурсу."
Add-Paragraph $parts "Інформаційна архітектура головної сторінки побудована за принципом поступового розкриття змісту. Спочатку користувач бачить коротку ідею сайту та кнопки дії, потім знайомиться з партнерами, напрямами діяльності, перевагами компанії, командою, відгуками, частими запитаннями та матеріалами блогу. Завершення сторінки формою підписки є логічним, оскільки після ознайомлення з основним змістом користувачу пропонується спосіб залишитися на зв’язку з компанією."
Add-Paragraph $parts "У межах аналізу предметної області також важливо враховувати, що зелена енергетика є темою, яка потребує довіри. Користувач повинен бачити, що компанія не лише використовує загальні екологічні гасла, а й подає конкретні напрями діяльності, приклади показників, команду та контактні дані. Саме тому в проєкті присутні числові показники, блок експертів, відгуки та FAQ, які разом створюють ширший контекст для сприйняття компанії."
Add-Paragraph $parts "Файлова структура проєкту є достатньо простою, однак вона демонструє базовий принцип поділу відповідальності між частинами вебсайту. HTML-файли відповідають за зміст і структуру, CSS-файл – за оформлення, JavaScript-файл – за поведінку, а папка «images» – за графічні ресурси. Такий поділ є важливим для навчального проєкту, тому що він формує правильне уявлення про організацію статичного вебсайту."

Add-PageBreak $parts
Add-Paragraph $parts "2 ВЕРСТКА СТОРІНОК САЙТУ" "H1"
Add-Paragraph $parts "Верстка сторінок виконана з використанням HTML-структури та спільного CSS-файла, у якому описано як загальні правила оформлення, так і стилі конкретних секцій. Оскільки сайт складається з кількох сторінок, важливим завданням було зберегти єдину візуальну мову, щоб користувач сприймав усі частини ресурсу як завершену систему."
Add-Paragraph $parts "У проєкті простежується поділ на повторювані елементи та унікальні інформаційні блоки. До повторюваних належать шапка сторінки, логотип, навігаційне меню, кнопка відкриття модального вікна, футер і кнопка прокрутки вгору. Унікальні блоки залежать від призначення сторінки та відображають інформацію про компанію, команду, контакти або тематичні матеріали."

Add-Paragraph $parts "2.1 Верстка головної сторінки «index.html»" "H2"
Add-Paragraph $parts "Головна сторінка є найбільш змістовною частиною сайту, оскільки саме вона формує перше враження про компанію та задає загальний тон усього вебресурсу. Перший екран реалізовано за допомогою елемента «header» з класами «main-header», «cover-bg» і «d-flex». У CSS для цього блока задано висоту на весь екран і фонове зображення «hero.jpg», що дозволяє зробити вступну секцію візуально виразною."
Add-Code $parts @'
<header class="main-header cover-bg d-flex">
  <nav class="header-nav">
    <div class="content-wrap d-flex justify-between vertical-center h-full">
      <div class="main-logo">
        <a href="index.html">
          <img src="images/logo.svg" alt="logo">
        </a>
      </div>
    </div>
  </nav>
</header>
'@
Add-Paragraph $parts "У цьому фрагменті видно, що логотип оформлено як посилання на головну сторінку, що є типовим рішенням для вебсайтів. Контейнер «content-wrap» обмежує ширину вмісту, тоді як класи «d-flex», «justify-between» і «vertical-center» відповідають за розміщення елементів у рядку."
Add-Paragraph $parts "Центральний блок першого екрана містить слоган «Енергія змін», заголовок «Рішення для сталого розвитку», опис і дві кнопки. Одна з кнопок має клас «header-btn-green», завдяки чому вона виділяється на фоні іншої кнопки та привертає увагу користувача до основної дії. Друга кнопка має клас «modal-btn», який використовується JavaScript-кодом для відкриття модального вікна."
Add-Paragraph $parts "Рисунок 2.1 – Перший екран головної сторінки вебсайту" "Figure"
Add-Paragraph $parts "Після головного екрана розташовано секцію «partners», де виводяться логотипи партнерів. У HTML вона складається з кількох порожніх блоків «partners-grid-item», а відповідні зображення задаються через CSS. Це рішення дозволяє зберігати HTML-структуру лаконічною, тоді як графічне наповнення контролюється таблицею стилів."
Add-Code $parts @'
.partners-grid-item-1 {
  background-image: url(../images/partners/1.svg);
}
.partners-grid-item-2 {
  background-image: url(../images/partners/2.svg);
}
'@
Add-Paragraph $parts "Промо-секція «promo-section» побудована як двоколонкова структура, де ліва частина містить перелік напрямів, а права частина представлена зображенням. Активний пункт списку має клас «list-item-active», завдяки чому він отримує розширений опис і візуальне виділення. Такий прийом допомагає акцентувати увагу на сонячній енергетиці, не перевантажуючи всю секцію великим обсягом тексту."
Add-Paragraph $parts "Секції «about» і «section-about-us» доповнюють одна одну: перша містить короткий опис діяльності та кількісні показники, а друга подає загальну характеристику компанії в більш презентаційній формі. Показники «5,000 Mwh», «2,500+», «10,000+» і «15%» винесені в окрему праву колонку, що робить їх помітними для користувача."
Add-Paragraph $parts "Рисунок 2.2 – Інформаційні блоки головної сторінки" "Figure"
Add-Paragraph $parts "Секція «section-expetrs» використовується для представлення експертів, які працюють у компанії. Картки формуються з блоків «experts-grid-item», де окремо розміщуються зображення, ім’я та посада. Хоча в назві класу «section-expetrs» є орфографічна неточність, у межах опису проєкту вона розглядається як фактична назва класу, що використана в коді."
Add-Paragraph $parts "Секція відгуків «section-testimonials» побудована на основі карток «testimonials-grid-item», які містять текст відгуку та блок із даними клієнта. Для цих карток у CSS передбачено ефект підняття при наведенні, що робить інтерфейс більш динамічним і показує користувачу, що елемент реагує на взаємодію."
Add-Code $parts @'
.testimonials-grid-item:hover {
  transform: translateY(-10px);
  transition: all .5s ease;
}
'@
Add-Paragraph $parts "У нижній частині головної сторінки розміщено секцію «faq-section», блоговий блок «blog-section» і секцію підписки «form-section». FAQ допомагає коротко пояснити базові питання, пов’язані із зеленою енергією, блоговий блок додає інформаційної глибини сайту, а форма підписки дозволяє змоделювати сценарій отримання оновлень від компанії."

Add-Paragraph $parts "2.2 Верстка сторінки «about.html»" "H2"
Add-Paragraph $parts "Сторінка «about.html» призначена для пояснення місії компанії та її підходу до впровадження енергетичних рішень. Вона використовує спільну шапку з класом «contact-header», завдяки якому верхній блок має меншу висоту, ніж головний екран на «index.html». Це доцільно для внутрішніх сторінок, оскільки вони не потребують такого великого вступного простору."
Add-Paragraph $parts "Основна секція «about-section» містить текстові блоки «Наша місія» та «Наш підхід», що дозволяє подати інформацію не у вигляді довгого суцільного тексту, а як два логічно відокремлені фрагменти. Поруч із текстом передбачено блок «about-section-img», який оформлено як фонове зображення."
Add-Code $parts @'
<section class="section about-section">
  <div class="content-wrap d-flex justify-between">
    <div class="about-section-info">
      <h2 class="section-title">Наша місія</h2>
      <p>Ми працюємо над тим, щоб зробити енергію доступною...</p>
    </div>
    <div class="about-section-img cover-bg"></div>
  </div>
</section>
'@
Add-Paragraph $parts "Наступний блок сторінки має клас «achievements-section» і містить короткі показники діяльності компанії. Завдяки використанню класів «achievements-grid» і «achievement-item» інформація подається у вигляді окремих елементів, які легко сприймаються під час перегляду сторінки. Після цього розміщено секцію «video-section», де за допомогою елемента «iframe» інтегровано відео з YouTube."
Add-Paragraph $parts "Рисунок 2.3 – Сторінка «Про нас» із блоками місії, досягнень і відео" "Figure"

Add-Paragraph $parts "2.3 Верстка сторінки «team.html»" "H2"
Add-Paragraph $parts "Сторінка «team.html» має просту, але зрозумілу структуру, оскільки її основна функція полягає в представленні команди. Кожен працівник описаний окремою секцією «team-member», у якій ліворуч розміщується інформація, а праворуч – зображення. Такий варіант компонування дозволяє зберегти однакову форму подання для всіх фахівців."
Add-Code $parts @'
<section class="team-member">
  <div class="content-wrap d-flex justify-between">
    <div class="team-member-info">
      <h2 class="team-member-name">Олександра Коваль</h2>
      <h3 class="team-member-position">Старший консультант</h3>
      <p class="team-member-description">займається аналізом сталих енергетичних рішень...</p>
    </div>
    <div class="team-member-img cover-bg"></div>
  </div>
</section>
'@
Add-Paragraph $parts "Для стилізації цієї сторінки у файлі «styles/style.css» визначено класи «team-member», «team-member-info», «team-member-name», «team-member-position», «team-member-description» і «team-member-img». Вони відповідають за відступи, розміри шрифтів, колір тексту, розміри фотографій і загальне розташування контенту."
Add-Code $parts @'
.team-member {
  display: flex;
  align-items: center;
  padding: 80px 0;
  width: 100%;
}
.team-member-img {
  width: 300px;
  height: 300px;
  background-position: center;
  background-size: cover;
  border-radius: 12px;
}
'@
Add-Paragraph $parts "Особливістю сторінки є чергування світлих фонових кольорів для секцій, яке реалізовано через CSS-селектори «nth-child». Завдяки цьому кожен блок із працівником відділяється від сусіднього, і сторінка не виглядає монотонною навіть тоді, коли всі елементи мають однакову структуру."
Add-Paragraph $parts "Рисунок 2.4 – Сторінка «Команда» з інформаційними блоками працівників" "Figure"

Add-Paragraph $parts "2.4 Верстка сторінки «contact.html»" "H2"
Add-Paragraph $parts "Сторінка «contact.html» виконує комунікаційну функцію, оскільки вона містить контактні дані компанії, форму для надсилання повідомлення та карту розташування. На відміну від головної сторінки, де форма є лише елементом підписки, контактна сторінка надає ширший набір полів для введення імені, пошти, телефону та тексту повідомлення."
Add-Code $parts @'
<form id="contactForm">
  <label for="name">Ім'я</label>
  <input type="text" id="name" name="name" required>

  <label for="email">Пошта</label>
  <input type="email" id="email" name="email" required>

  <label for="message">Повідомлення</label>
  <textarea id="message" name="message" rows="5" required></textarea>
</form>
'@
Add-Paragraph $parts "У формі використано атрибут «required», завдяки якому браузер виконує базову перевірку заповнення полів перед надсиланням. Для поля електронної пошти вказано тип «email», що також допомагає перевірити правильність введеного значення без додаткового JavaScript-коду."
Add-Paragraph $parts "Контактна інформація розміщена в блоці «contact-info», де телефон оформлено через посилання «tel», а електронну адресу – через «mailto». Це зручно для користувача, оскільки на підтримуваних пристроях натискання на такі посилання може одразу ініціювати дзвінок або створення листа."
Add-Paragraph $parts "Карта розміщена у секції «map-section» через елемент «iframe». Для контейнера «map-container» у CSS задано заокруглення кутів, приховування переповнення та тінь, завдяки чому карта візуально відділяється від фону сторінки."
Add-Paragraph $parts "Рисунок 2.5 – Сторінка «Контакти» з формою і картою" "Figure"

Add-Paragraph $parts "2.5 Організація стилізації у файлі «styles/style.css»" "H2"
Add-Paragraph $parts "Файл «styles/style.css» виконує роль єдиного центру оформлення сторінок. На початку файла розміщено базове скидання відступів і налаштування моделі розрахунку розмірів елементів, що допомагає уникнути непередбачуваних відмінностей між браузерами. Далі визначено стилі для тіла документа, зображень, посилань, списків і допоміжних класів."
Add-Code $parts @'
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: "Open Sans", serif;
  font-weight: 400;
  color: #1D1F1E;
}
'@
Add-Paragraph $parts "Колірна схема сайту базується на поєднанні темного зеленого кольору, світлого лаймового акценту, білого фону та м’якого теплого відтінку для інформаційних блоків. Таке оформлення відповідає тематиці зеленої енергетики, оскільки зелений колір асоціюється з екологічністю, а світлі фони забезпечують достатню читабельність."
Add-Paragraph $parts "Стилі кнопок винесено в клас «header-btn», який використовується в різних частинах сайту. Модифікатор «header-btn-green» змінює фон і колір кнопки, що дозволяє виділяти основну дію. Такий підхід наближає структуру CSS до компонентної логіки, коли базовий клас визначає загальну форму, а додатковий клас уточнює зовнішній вигляд."
Add-Code $parts @'
.header-btn {
  padding: 12px 20px;
  border-radius: 200px;
  border: 1px solid #fff;
  background-color: transparent;
  color: #fff;
  font-weight: 500;
  cursor: pointer;
}

.header-btn-green {
  background-color: #BEF264;
  color: #1D1F1E;
  border: none;
}
'@
Add-Paragraph $parts "Під час верстки головної сторінки важливим було поєднати великі презентаційні блоки з компактними інформаційними елементами. Перший екран має значну висоту та великий заголовок, тоді як наступні секції поступово зменшують візуальний масштаб і переходять до більш конкретних відомостей. Такий перехід допомагає уникнути різкого інформаційного навантаження, оскільки користувач спочатку сприймає загальну ідею, а вже потім переходить до деталей."
Add-Paragraph $parts "У секції «promo-section» застосовано поєднання текстового списку та зображення, що є доцільним для тематики енергетичних рішень. Якщо перелік напрямів був би поданий без візуального супроводу, секція виглядала б сухо й менш переконливо. Водночас надмірна кількість зображень могла б відволікати від змісту, тому в реалізації використано один великий графічний блок, який підтримує загальний настрій секції."
Add-Paragraph $parts "Секція «about» відрізняється від інших тим, що має заокруглений контейнер і теплий фоновий відтінок. Таке оформлення відділяє її від білих секцій і підкреслює, що цей блок містить важливу узагальнену інформацію про компанію. Кількісні показники розміщені праворуч, тому вони візуально сприймаються як короткі докази результативності, а не як частина довгого описового тексту."
Add-Paragraph $parts "Блок експертів на головній сторінці та сторінка «team.html» частково дублюють одну інформаційну ідею, однак виконують різні функції. На головній сторінці експерти подані компактно, щоб користувач швидко побачив наявність команди. На сторінці «team.html» кожен фахівець має окремий блок із більшим описом, через що сторінка виконує роль деталізованого представлення персоналу."
Add-Paragraph $parts "Секція відгуків є важливою для презентаційного вебсайту, оскільки вона створює ефект соціального підтвердження. У межах цього проєкту відгуки реалізовані як статичні картки, де текст клієнта поєднано з іменем, статусом і зображенням. Таке рішення не потребує складного JavaScript-функціоналу, але виконує свою інформаційну функцію та органічно доповнює структуру головної сторінки."
Add-Paragraph $parts "FAQ-блок реалізовано у вигляді послідовності запитань і відповідей, які розміщені у правій колонці. Такий формат зручний для теми зеленої енергетики, оскільки користувач може мати базові питання щодо принципу роботи сонячних панелей, користі зеленої енергії або переліку рішень, які пропонує компанія. У поточній реалізації блок не має розгортання або згортання відповідей, проте його статичний варіант залишається зрозумілим і доступним."
Add-Paragraph $parts "Блоговий блок на головній сторінці не реалізує повноцінної системи статей, але виконує роль візуального анонсу тематичних матеріалів. У ньому використано три картки, кожна з яких має зображення, заголовок, автора та час читання. Завдяки цьому користувач бачить, що компанія може не лише надавати послуги, а й поширювати корисну інформацію у сфері енергетики."
Add-Paragraph $parts "Сторінка «about.html» є порівняно короткою, однак вона виконує важливе завдання, оскільки пояснює, на яких засадах працює компанія. Вміст сторінки поділено на місію, підхід, досягнення та відео. Така структура дозволяє не перевантажувати сторінку зайвими деталями, водночас залишаючи достатньо матеріалу для розуміння позиціонування організації."
Add-Paragraph $parts "Сторінка «team.html» побудована за повторюваним шаблоном, і це є доцільним рішенням для сторінок, де потрібно представити кілька однотипних об’єктів. Кожен блок має однакову структуру, що дозволяє користувачу швидко порівнювати інформацію про працівників. За потреби в майбутньому до такої структури можна додати нових членів команди без зміни загальної логіки верстки."
Add-Paragraph $parts "Контактна сторінка є однією з ключових для корпоративного сайту, тому що саме вона переводить інформаційний інтерес користувача в можливість реальної взаємодії. У проєкті ця сторінка містить не лише текстові контактні дані, а й форму та карту, завдяки чому вона охоплює кілька способів комунікації. Такий підхід є практичним, оскільки різні користувачі можуть надавати перевагу різним каналам зв’язку."
Add-Paragraph $parts "Загалом верстка сторінок демонструє використання простих, але зрозумілих підходів: блокової структури, Flexbox-вирівнювання, фонових зображень, повторюваних класів, форм і карток. Оскільки проєкт є навчальним, важливо, що його структура залишається відкритою для подальшого редагування. Кожну секцію можна окремо доповнювати, змінювати або переносити без повної перебудови сайту."

Add-PageBreak $parts
Add-Paragraph $parts "3 РОЗРОБКА ФУНКЦІОНАЛЬНИХ КОМПОНЕНТІВ СТОРІНОК" "H1"
Add-Paragraph $parts "Функціональна частина проєкту реалізована у файлі «script/app.js». Оскільки сайт є статичним і не використовує серверну логіку, JavaScript застосовано лише для тих елементів, які повинні реагувати на дії користувача без перезавантаження сторінки. До таких елементів належать кнопка прокрутки вгору та модальне вікно з формою зв’язку."

Add-Paragraph $parts "3.1 Реалізація кнопки прокрутки вгору" "H2"
Add-Paragraph $parts "Кнопка прокрутки вгору потрібна через те, що головна сторінка має значну висоту та містить багато секцій. Якщо користувач переглядає нижню частину сторінки, можливість швидко повернутися до початку покращує зручність роботи з вебресурсом. Елемент кнопки має ідентифікатор «scrollToTop» і розміщується наприкінці HTML-документа."
Add-Code $parts @'
<button id="scrollToTop" class="scroll-to-top">
  <i class="fa-solid fa-arrow-up"></i>
</button>
'@
Add-Paragraph $parts "У CSS для класу «scroll-to-top» задано фіксоване позиціонування в нижньому правому куті екрана, округлу форму, фоновий колір і початковий стан «display: none». Це означає, що кнопка не відображається відразу після завантаження сторінки, а з’являється лише тоді, коли користувач прокручує сторінку вниз."
Add-Code $parts @'
const scrollToTopBtn = document.getElementById("scrollToTop");

window.addEventListener("scroll", () => {
  if (window.scrollY > 300) {
    scrollToTopBtn.style.display = "flex";
  } else {
    scrollToTopBtn.style.display = "none";
  }
});
'@
Add-Paragraph $parts "У наведеному фрагменті JavaScript-коду використано обробник події «scroll», який перевіряє вертикальне зміщення сторінки за допомогою властивості «window.scrollY». Якщо значення перевищує 300 пікселів, кнопка відображається як flex-контейнер, а якщо користувач повертається вище, вона знову приховується."
Add-Code $parts @'
scrollToTopBtn.addEventListener("click", () => {
  window.scrollTo({
    top: 0,
    behavior: "smooth",
  });
});
'@
Add-Paragraph $parts "Після натискання на кнопку викликається метод «window.scrollTo», у якому параметр «top: 0» задає повернення до верхньої частини сторінки, а параметр «behavior: smooth» забезпечує плавність анімації. Завдяки цьому перехід не сприймається різким і краще відповідає загальному характеру інтерфейсу."
Add-Paragraph $parts "Рисунок 3.1 – Кнопка прокрутки сторінки вгору" "Figure"

Add-Paragraph $parts "3.2 Реалізація модального вікна" "H2"
Add-Paragraph $parts "Модальне вікно використовується для швидкого відкриття форми зв’язку без переходу на окрему сторінку. У HTML воно описане блоком із ідентифікатором «contactModal» і класом «modal», усередині якого розташовано контейнер «modal-content». Така структура дозволяє створити затемнену область на весь екран і розмістити форму по центру."
Add-Code $parts @'
<div id="contactModal" class="modal">
  <div class="modal-content">
    <span class="close-btn">&times;</span>
    <h2>Зв'язатися</h2>
    <form id="contactForm">
      <input type="text" id="name" name="name" required>
    </form>
  </div>
</div>
'@
Add-Paragraph $parts "Стилі модального вікна передбачають, що воно займає всю ширину і висоту екрана, має напівпрозорий темний фон і розміщує вміст по центру. Початкове значення «display: none» приховує модальне вікно до моменту взаємодії користувача з кнопкою."
Add-Code $parts @'
.modal {
  display: none;
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0, 0, 0, 0.5);
  justify-content: center;
  align-items: center;
  z-index: 1000;
}
'@
Add-Paragraph $parts "У JavaScript-коді елемент модального вікна отримується через «getElementById», а всі кнопки відкриття вибираються за класом «modal-btn». Оскільки таких кнопок на сторінках може бути кілька, використано метод «querySelectorAll» і цикл «forEach», який призначає обробник події кожній кнопці."
Add-Code $parts @'
const modal = document.getElementById("contactModal");
const openButtons = document.querySelectorAll(".modal-btn");
const closeModalBtn = document.querySelector(".close-btn");

openButtons.forEach((button) => {
  button.addEventListener("click", () => {
    modal.style.display = "flex";
  });
});
'@
Add-Paragraph $parts "Закриття модального вікна реалізовано двома способами. Перший спосіб полягає в натисканні на елемент «close-btn», після чого для модального блоку встановлюється «display: none». Другий спосіб передбачає клік по зовнішній затемненій області, коли об’єкт події збігається з самим елементом «modal»."
Add-Code $parts @'
closeModalBtn.addEventListener("click", () => {
  modal.style.display = "none";
});

window.addEventListener("click", (e) => {
  if (e.target === modal) {
    modal.style.display = "none";
  }
});
'@
Add-Paragraph $parts "Така логіка робить компонент інтуїтивним для користувача, оскільки модальне вікно можна закрити не лише спеціальною кнопкою, а й кліком поза межами форми. Це відповідає поширеним сценаріям взаємодії з модальними елементами на сучасних вебсайтах."
Add-Paragraph $parts "Рисунок 3.2 – Модальне вікно з формою зв’язку" "Figure"

Add-Paragraph $parts "3.3 Форми та базова перевірка введених даних" "H2"
Add-Paragraph $parts "У проєкті використано кілька форм, які виконують різні комунікаційні функції. На головній сторінці форма «form» у секції «form-section» призначена для підписки на оновлення, тоді як форма на сторінці «contact.html» і форма в модальному вікні призначені для зв’язку з компанією. Хоча серверна обробка не реалізована, структура форм підготовлена таким чином, щоб у майбутньому її можна було підключити до бекенд-частини або зовнішнього сервісу."
Add-Paragraph $parts "Для базової перевірки введення застосовано HTML-атрибути «type» і «required». Поле з типом «email» дає змогу браузеру визначити, чи введене значення схоже на адресу електронної пошти, а атрибут «required» не дозволяє надсилати порожню форму. Такі можливості не замінюють повноцінної серверної перевірки, однак вони покращують якість взаємодії на клієнтському рівні."
Add-Paragraph $parts "Оформлення полів контактної форми включає стани фокуса, які допомагають користувачу бачити, з яким полем він працює. У CSS це реалізовано через селектори «contact-form input:focus» і «contact-form textarea:focus», де змінюється колір рамки та додається тінь."
Add-Code $parts @'
.contact-form input:focus,
.contact-form textarea:focus {
  border-color: #BEF264;
  box-shadow: 0 0 0 4px rgba(190, 242, 100, 0.4);
  outline: none;
}
'@
Add-Paragraph $parts "Завдяки такому оформленню форма виглядає не як статичний набір полів, а як інтерактивний елемент, що реагує на дії користувача. Це важливо для контактної сторінки, оскільки саме через форму користувач може залишити повідомлення або ініціювати подальшу комунікацію з компанією."
Add-Paragraph $parts "Під час розроблення функціональної частини було важливо не перевантажувати сайт сценаріями, які не мають практичного значення для поточної структури. Оскільки проєкт не містить каталогу, особистого кабінету або динамічного завантаження даних, JavaScript використано лише там, де він безпосередньо покращує взаємодію. Такий підхід відповідає принципу доцільності, коли кожен скрипт має зрозумілу мету."
Add-Paragraph $parts "Кнопка прокрутки вгору є невеликим, але корисним компонентом, оскільки вона враховує реальну довжину головної сторінки. Без такої кнопки користувачеві довелося б вручну повертатися до верхньої частини сторінки, що є незручним після перегляду FAQ, блогу або форми підписки. Реалізація компонента не потребує складної логіки, проте демонструє вміння працювати з подіями браузера."
Add-Paragraph $parts "Модальне вікно є більш помітним функціональним елементом, оскільки воно пов’язане з кнопками «Зв'язатися», які розміщені в різних частинах сайту. Завдяки використанню класу «modal-btn» усі такі кнопки можуть відкривати один і той самий блок, що зменшує дублювання коду. Якщо в майбутньому потрібно буде додати ще одну кнопку відкриття форми, достатньо буде надати їй той самий клас."
Add-Paragraph $parts "У поточному JavaScript-коді не використано складних бібліотек, що є перевагою для невеликого статичного вебсайту. Відсутність сторонніх сценаріїв зменшує залежність проєкту від зовнішніх ресурсів і робить логіку прозорою для аналізу. У навчальному контексті це також важливо, оскільки весь функціонал можна пояснити без звернення до складних фреймворків."
Add-Paragraph $parts "Варто зазначити, що форми в проєкті виконують клієнтську роль і не мають серверної обробки. Це означає, що після натискання кнопки дані не надсилаються до бази даних або поштового сервера. Однак HTML-структура форм уже містить основні поля, тому за потреби її можна буде інтегрувати з серверною частиною, форм-сервісом або API для надсилання повідомлень."
Add-Paragraph $parts "Інтерактивність у цьому проєкті має підтримувальний характер, оскільки головна цінність сайту полягає в інформаційному представленні компанії. Водночас навіть невеликі інтерактивні елементи суттєво впливають на сприйняття ресурсу, адже вони створюють відчуття живого інтерфейсу. Саме тому кнопка прокрутки, модальне вікно та стани фокуса у формах є важливими для загального користувацького досвіду."
Add-Paragraph $parts "Під час подальшого розвитку JavaScript-частини можна було б додати обробник надсилання форми, повідомлення про успішне заповнення, перевірку номера телефону або закриття модального вікна клавішею «Escape». Проте в межах поточної реалізації описані компоненти вже демонструють базові принципи роботи з DOM-елементами, подіями та зміною стилів через JavaScript."

Add-PageBreak $parts
Add-Paragraph $parts "4 ТЕСТУВАННЯ ТА ПІДГОТОВКА ПРОЄКТУ" "H1"
Add-Paragraph $parts "Після завершення верстки та реалізації інтерактивних компонентів необхідно перевірити, чи всі сторінки коректно відкриваються у браузері, чи працюють переходи між основними розділами, чи завантажуються графічні ресурси та чи правильно реагують елементи, для яких написано JavaScript-код. Для статичного вебсайту така перевірка є особливо важливою, оскільки навіть незначна помилка у шляху до файла може призвести до відсутності зображення або стилів."
Add-Paragraph $parts "Передусім перевіряється головна сторінка «index.html», оскільки вона містить найбільшу кількість секцій і використовує більшість стилів проєкту. Необхідно переконатися, що фонове зображення першого екрана, логотип, партнерські зображення, фотографії експертів, зображення клієнтів і матеріали блогового блоку коректно відображаються. Оскільки частина зображень підключена не через тег «img», а через CSS-властивість «background-image», перевірка має охоплювати і HTML, і файл «styles/style.css»."
Add-Paragraph $parts "На сторінці «about.html» перевіряється відображення текстових блоків, секції досягнень і відео, яке вбудоване через елемент «iframe». На сторінці «team.html» потрібно переглянути всі блоки «team-member», щоб переконатися, що дані працівників відображаються послідовно, а зображення не виходять за межі контейнерів. На сторінці «contact.html» перевіряються посилання на телефон і електронну пошту, форма повідомлення та карта."
Add-Paragraph $parts "Рисунок 4.1 – Перевірка відображення головної сторінки у браузері" "Figure"
Add-Paragraph $parts "Окремий етап тестування стосується JavaScript-функціоналу. Кнопка «scrollToTop» повинна бути прихованою у верхній частині сторінки, з’являтися після прокручування вниз і плавно повертати користувача на початок після натискання. Модальне вікно «contactModal» повинно відкриватися після натискання на кнопки з класом «modal-btn» і закриватися за допомогою елемента «close-btn» або кліку по затемненій області."
Add-Paragraph $parts "Рисунок 4.2 – Перевірка роботи модального вікна" "Figure"
Add-Paragraph $parts "Для перевірки якості HTML-коду доцільно використати валідатор W3C, оскільки він дозволяє виявити порушення структури документа, некоректні атрибути або дублювання ідентифікаторів. CSS-код можна перевірити за допомогою CSS Validator, який показує синтаксичні помилки та властивості, що можуть бути не підтримані або записані неправильно."
Add-Paragraph $parts "Під час підготовки проєкту до публікації потрібно перевірити, чи всі посилання є відносними, чи зберігається структура папок, чи немає випадково перейменованих файлів і чи всі ресурси доступні з кореня проєкту. Оскільки сайт не потребує серверної логіки, його можна розмістити на статичному хостингу, який підтримує HTML, CSS, JavaScript і графічні файли."
Add-Paragraph $parts "Рисунок 4.3 – Перевірка сторінки «Контакти»" "Figure"
Add-Paragraph $parts "У результаті тестування має бути підтверджено, що вебсайт виконує основні завдання: презентує компанію, дозволяє переглянути інформаційні сторінки, забезпечує доступ до контактів, демонструє тематичні матеріали та надає базові інтерактивні можливості. Якщо виявляються помилки у шляхах, дублювання атрибутів або неточності стилізації, їх потрібно усунути до остаточного оформлення курсового проєкту."
Add-Paragraph $parts "Під час ручного тестування особливу увагу потрібно приділити однаковості відображення спільних елементів на різних сторінках. Якщо шапка, футер або модальне вікно відрізнятимуться без змістової причини, користувач може сприйняти сайт як неузгоджений. Тому перевірка повторюваних елементів є не менш важливою, ніж перевірка унікальних секцій."
Add-Paragraph $parts "Оскільки у проєкті використовується багато фонових зображень, окремо перевіряється правильність шляхів до графічних файлів. У CSS шляхи записуються відносно розташування файла «styles/style.css», тому зображення підключаються через конструкції на зразок «url(../images/hero.jpg)». Якщо структура папок буде змінена, такі шляхи потрібно буде оновити, інакше частина візуального оформлення зникне."
Add-Paragraph $parts "Для перевірки контактної сторінки важливо не лише переглянути зовнішній вигляд форми, а й протестувати поведінку полів із різними типами введення. Наприклад, поле з типом «email» повинно реагувати на некоректну адресу, а обов’язкові поля не повинні дозволяти надсилати порожню форму. Така перевірка підтверджує, що базові HTML-механізми валідації працюють належним чином."
Add-Paragraph $parts "Під час тестування модального вікна потрібно перевірити всі кнопки, які мають клас «modal-btn», оскільки саме цей клас використовується для призначення обробника відкриття. Якщо якась кнопка не має цього класу, вона не відкриватиме форму, навіть якщо візуально виглядатиме як елемент зв’язку. Тому відповідність HTML-класів і JavaScript-логіки є важливою умовою працездатності компонента."
Add-Paragraph $parts "Також потрібно перевірити поведінку сторінки після тривалого прокручування, оскільки кнопка «scrollToTop» залежить від значення «window.scrollY». Якщо елемент кнопки відсутній у HTML або його ідентифікатор змінено, JavaScript-код не зможе коректно отримати посилання на нього. У поточному проєкті цей елемент наявний на основних сторінках, що забезпечує роботу сценарію."
Add-Paragraph $parts "Публікація статичного сайту потребує уважного ставлення до регістру літер у назвах файлів, оскільки деякі хостинги розрізняють великі й малі літери. У локальному середовищі Windows така проблема може бути непомітною, однак після розміщення на сервері неправильний регістр у шляху до зображення або сторінки може призвести до помилки завантаження. Тому перед публікацією доцільно переглянути всі посилання та назви ресурсів."
Add-Paragraph $parts "Ще одним напрямом перевірки є читабельність тексту на контрастних фонах. У проєкті частина тексту розміщена поверх темних фонових зображень або темно-зелених блоків, тому потрібно переконатися, що білий текст залишається добре видимим. Якщо певне фонове зображення має надто світлі ділянки, у майбутньому можна додати затемнення або змінити позицію текстового блоку."
Add-Paragraph $parts "Підготовка проєкту до захисту також передбачає формування візуальних матеріалів для рисунків у пояснювальній записці. Доцільно зробити скріншоти першого екрана головної сторінки, секції з інформацією про компанію, сторінки команди, сторінки контактів, модального вікна та фрагмента коду. Такі рисунки допоможуть пов’язати текстовий опис із фактичним виглядом реалізованого вебсайту."

Add-PageBreak $parts
Add-Paragraph $parts "ВИСНОВКИ" "H1"
Add-Paragraph $parts "У процесі виконання курсового проєкту було розроблено вебсайт компанії у сфері зеленої енергетики, який складається з головної сторінки, сторінки з інформацією про компанію, сторінки команди та сторінки контактів. Розроблений ресурс має презентаційний характер і призначений для ознайомлення користувачів із напрямом діяльності компанії, її підходом до роботи, фахівцями, контактними даними та тематичними матеріалами."
Add-Paragraph $parts "Під час роботи було використано HTML для побудови структури сторінок, CSS для створення зовнішнього вигляду та JavaScript для реалізації інтерактивних компонентів. У файлі «styles/style.css» описано загальні правила оформлення, допоміжні класи, стилі секцій, карток, форм, футера, сторінки команди та контактної сторінки. У файлі «script/app.js» реалізовано показ кнопки прокрутки вгору, плавне повернення до початку сторінки, відкриття і закриття модального вікна."
Add-Paragraph $parts "Головна сторінка «index.html» стала центральною частиною проєкту, оскільки вона містить перший екран, блок партнерів, промо-секцію, інформацію про компанію, перелік експертів, відгуки клієнтів, відповіді на поширені запитання, блоговий блок і форму підписки. Сторінка «about.html» деталізує місію та підхід компанії, «team.html» презентує працівників, а «contact.html» забезпечує комунікацію через контактну інформацію, форму та карту."
Add-Paragraph $parts "У процесі створення сайту було закріплено практичні навички організації багатосторінкового проєкту, роботи з фоновими зображеннями, застосування Flexbox, оформлення форм, підключення зовнішніх шрифтів та іконок, а також написання простих сценаріїв JavaScript. Окрему увагу приділено тому, щоб сторінки мали спільні елементи інтерфейсу, оскільки це забезпечує цілісність візуального сприйняття вебресурсу."
Add-Paragraph $parts "Розроблений вебсайт може бути основою для подальшого вдосконалення. У майбутньому його можна доповнити адаптивним мобільним меню, серверною обробкою форм, сторінками окремих послуг, повноцінним блогом, покращеною оптимізацією зображень і розширеним тестуванням швидкодії. Водночас у межах курсового проєкту реалізовано основну структуру, візуальне оформлення та базову інтерактивність, які відповідають темі розроблення сайту компанії у сфері зеленої енергетики."

$documentBody = ($parts -join "`n")

$documentXml = @"
<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
  <w:body>
    $documentBody
    <w:sectPr>
      <w:pgSz w:w="11906" w:h="16838"/>
      <w:pgMar w:top="1134" w:right="850" w:bottom="1134" w:left="1701" w:header="708" w:footer="708" w:gutter="0"/>
      <w:cols w:space="708"/>
      <w:docGrid w:linePitch="360"/>
    </w:sectPr>
  </w:body>
</w:document>
"@

$stylesXml = @"
<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">
